/*
* By Diego Tapia
*/

let clone = this.CQP_START_CLONE
window.processId = this._request.process_id
const myInterval = setInterval(mytimer, 500);

function mytimer() {
  let el = document.querySelector('[selector="start_clone"] button');

  if (el != null && el != undefined && el != "") {
    clearInterval(myInterval);

    if (window.eventCreated != true) {
      window.eventCreated = true

      el.addEventListener('click', () => {
          if (window.createStart != true) {
            window.createStart = true

            ProcessMaker.apiClient.post('webentry/processes/' + window.processId + '/web_entries/clone_start/start', {data:{CQP_CONTINUE: false}}).then(res => {
              window.newRequest = res.data.id
              let submitButton = document.querySelector('[selector="clone"] button');
              submitButton.click();
            });
          }
      });
    }
  }
}

/*
* By Diego Tapia
*/

const list = this.CQP_QUOTATION_OPTIONS.CQP_BROKER_REQUESTS || [];
let CQP_FX_RATE = this.CQP_FX_RATE 
let CQP_CURRENCY = this.CQP_CURRENCY 
const len  = list.length;
let output = "";
let selectedRecords = 0;

for (let i = 0; i < len; i++) {
    if (list[i].SELECTED_RECORD_BROKER == true) {
        selectedRecords++;
    }
}

if (selectedRecords > 1) {
    output += 'You must select only one option.';
} else if(selectedRecords == 0) {
    output += 'You must select at least 1 row.';
}

if ((CQP_FX_RATE == null || CQP_FX_RATE == undefined || CQP_FX_RATE == "") && CQP_CURRENCY != "USD") {
    output += (output != "" ? "<br>" : "") + "You need to fill the FX rate Field"
}

return output;

